on conflict (source_car_id) do update set
  source_group_id = excluded.source_group_id,
  car_number = excluded.car_number,
  name = excluded.name,
  display_name = excluded.display_name,
  image_url = excluded.image_url,
  model_year = excluded.model_year,
  fuel_type = excluded.fuel_type,
  seats = excluded.seats,
  color = excluded.color,
  rent_age = excluded.rent_age,
  active = excluded.active,
  options_json = excluded.options_json,
  metadata = excluded.metadata,
  updated_at = now();

-- Phase 4 sample reservations
with reservation_input (
  reservation_code,
  source_car_id,
  status,
  pickup_option,
  delivery_region_id,
  start_at,
  end_at
) as (
  values
    ('S01A', 233063, 'confirmed', 'pickup', null, '2026-04-16 09:00:00+09', '2026-04-17 11:00:00+09'),
    ('S02A', 226059, 'confirmed', 'pickup', null, '2026-04-18 08:00:00+09', '2026-04-20 12:00:00+09'),
    ('S03A', 225595, 'pending', 'pickup', null, '2026-04-19 10:00:00+09', '2026-04-21 14:00:00+09'),
    ('S04LONG', 221617, 'paid', 'pickup', null, '2026-04-22 07:00:00+09', '2026-04-27 20:00:00+09'),
    ('S07DEL', 224219, 'confirmed', 'delivery', '1', '2026-04-16 07:00:00+09', '2026-04-17 12:00:00+09'),
    ('S08DEL', 221097, 'confirmed', 'delivery', '436', '2026-04-16 13:00:00+09', '2026-04-16 21:00:00+09')
)
insert into public.ims_sync_reservations (
  ims_reservation_id,
  source,
  car_id,
  car_number,
  car_group_id,
  status,
  status_raw,
  pickup_option,
  delivery_region_id,
  start_at,
  end_at,
  customer_name,
  customer_phone,
  last_synced_at
)
select
  format('shadow-%s', r.reservation_code),
  'shadow-seed',
  c.id::text,
  c.car_number,
  coalesce(c.source_group_id::text, ''),
  r.status,
  r.status,
  r.pickup_option,
  r.delivery_region_id,
  r.start_at::timestamptz,
  r.end_at::timestamptz,
  '테스트 고객',
  '01000000000',
  now()
from reservation_input r
join public.cars c on c.source_car_id = r.source_car_id
on conflict (ims_reservation_id) do nothing;
